23	/// Canonical-onboarding-sequence is StateProgressing — case N's hallmark/scratch
24	/// state establishes preconditions for case N+1, so engine keep-going is refused.
25	#[test]
26	fn rbtdto_disposition_is_state_progressing() {
27	    let fix = rbtdrc_lookup_fixture(RBTDRM_FIXTURE_CANONICAL_ONBOARDING_SEQUENCE)
28	        .expect("canonical-onboarding-sequence is registered");
29	    assert_eq!(fix.disposition, rbtdre_Disposition::StateProgressing);
30	}
31	
32	/// Sections lookup binds the fixture name to the registry array and yields
33	/// exactly five cases (1 inscribe + 4 ordain) under one section
34	/// ("canonical-onboarding-arc").
35	#[test]
36	fn rbtdto_sections_registered() {
37	    let fix = rbtdrc_lookup_fixture(RBTDRM_FIXTURE_CANONICAL_ONBOARDING_SEQUENCE)
38	        .expect("canonical-onboarding-sequence is registered");
39	    let sections = fix.sections;
40	    assert_eq!(sections.len(), 1, "expected one section");
41	    assert_eq!(sections[0].name, "canonical-onboarding-arc");
42	    assert_eq!(sections[0].cases.len(), 5, "expected five cases");
43	    let names: Vec<&str> = sections[0].cases.iter().map(|c| c.name).collect();
44	    assert!(names.iter().any(|n| n.contains("rbtdro_inscribe_reliquary")));
45	    assert!(names.iter().any(|n| n.contains("rbtdro_ordain_conjure")));
46	    assert!(names.iter().any(|n| n.contains("rbtdro_ordain_airgap")));
47	    assert!(names.iter().any(|n| n.contains("rbtdro_ordain_bind")));
48	    assert!(names.iter().any(|n| n.contains("rbtdro_ordain_graft")));
49	}
50	
51	/// Case order is load-bearing for StateProgressing — inscribe must precede
52	/// the conjure/airgap cases that read the reliquary scratch.
53	#[test]
54	fn rbtdto_inscribe_precedes_reliquary_consumers() {
55	    let fix = rbtdrc_lookup_fixture(RBTDRM_FIXTURE_CANONICAL_ONBOARDING_SEQUENCE)
56	        .expect("canonical-onboarding-sequence is registered");
57	    let sections = fix.sections;
58	    let names: Vec<&str> = sections[0].cases.iter().map(|c| c.name).collect();
59	    let inscribe_idx = names
60	        .iter()
61	        .position(|n| n.contains("rbtdro_inscribe_reliquary"))
62	        .expect("inscribe case present");
63	    let conjure_idx = names
64	        .iter()
65	        .position(|n| n.contains("rbtdro_ordain_conjure"))
66	        .expect("conjure case present");
67	    let airgap_idx = names
68	        .iter()
69	        .position(|n| n.contains("rbtdro_ordain_airgap"))
70	        .expect("airgap case present");
71	    assert!(inscribe_idx < conjure_idx);
72	    assert!(inscribe_idx < airgap_idx);
73	}
