211	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
212	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
213	    let required = match rbtdrm_required_colophons(fixture) {
214	        Some(r) => r,
215	        None => {
216	            return Err(format!(
217	                "rbtd: unknown fixture '{}' — not registered in manifest",
218	                fixture
219	            ));
220	        }
221	    };
222	    for colophon in required {
223	        let found = manifest.split_whitespace().any(|token| token == *colophon);
224	        if !found {
225	            return Err(format!(
226	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
227	                colophon, fixture
228	            ));
229	        }
230	    }
231	    Ok(())
232	}
