89	// ── Tabtarget discovery ──────────────────────────────────────
90	
91	/// Find the tabtarget script for a colophon + imprint (nameplate or role).
92	///
93	/// Scans tt/ for files matching `{colophon}.*.{imprint}.sh`.
94	/// Returns error if zero or multiple matches — exactly one must exist.
95	pub fn rbtdri_find_tabtarget(
96	    project_root: &Path,
97	    colophon: &str,
98	    imprint: &str,
99	) -> Result<PathBuf, String> {
100	    let tt_dir = project_root.join("tt");
101	    let prefix = format!("{}.", colophon);
102	    let suffix = format!(".{}.sh", imprint);
103	
104	    let entries = std::fs::read_dir(&tt_dir)
105	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
106	
107	    let matches: Vec<PathBuf> = entries
108	        .filter_map(|entry| entry.ok())
109	        .map(|entry| entry.path())
110	        .filter(|path| {
111	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
112	                name.starts_with(&prefix) && name.ends_with(&suffix)
113	            } else {
114	                false
115	            }
116	        })
117	        .collect();
118	
119	    match matches.len() {
120	        0 => Err(format!(
121	            "rbtdri: no tabtarget for colophon '{}' imprint '{}'",
122	            colophon, imprint
123	        )),
124	        1 => Ok(matches.into_iter().next().unwrap()),
125	        n => Err(format!(
126	            "rbtdri: {} tabtargets match colophon '{}' imprint '{}' — expected exactly one",
127	            n, colophon, imprint
128	        )),
129	    }
130	}
131	
132	/// Find a global tabtarget (no imprint suffix).
133	///
134	/// Scans tt/ for files matching `{colophon}.{frontispiece}.sh` (exactly two dots).
135	/// Rejects files with imprint suffixes (three+ dots).
136	pub fn rbtdri_find_tabtarget_global(
137	    project_root: &Path,
138	    colophon: &str,
139	) -> Result<PathBuf, String> {
140	    let tt_dir = project_root.join("tt");
141	    let prefix = format!("{}.", colophon);
142	
143	    let entries = std::fs::read_dir(&tt_dir)
144	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
145	
146	    let matches: Vec<PathBuf> = entries
147	        .filter_map(|entry| entry.ok())
148	        .map(|entry| entry.path())
149	        .filter(|path| {
150	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
151	                if name.starts_with(&prefix) && name.ends_with(".sh") {
152	                    // Global: no imprint — exactly one part between colophon and .sh
153	                    let middle = &name[prefix.len()..name.len() - 3]; // strip ".sh"
154	                    !middle.contains('.')
155	                } else {
156	                    false
157	                }
158	            } else {
159	                false
160	            }
161	        })
162	        .collect();
163	
164	    match matches.len() {
165	        0 => Err(format!(
166	            "rbtdri: no global tabtarget for colophon '{}'",
167	            colophon
168	        )),
169	        1 => Ok(matches.into_iter().next().unwrap()),
170	        n => Err(format!(
171	            "rbtdri: {} global tabtargets match colophon '{}' — expected exactly one",
172	            n, colophon
173	        )),
174	    }
175	}
