177	// ── Tabtarget invocation with BURV isolation ─────────────────
178	
179	/// Internal: execute a resolved tabtarget with BURV isolation and optional extra env vars.
180	fn rbtdri_invoke_impl(
181	    ctx: &mut rbtdri_Context,
182	    tabtarget: &Path,
183	    args: &[&str],
184	    extra_env: &[(&str, &str)],
185	) -> Result<rbtdri_InvokeResult, String> {
186	    let invoke_num = ctx.invoke_count;
187	    ctx.invoke_count += 1;
188	
189	    let invoke_dir = ctx.burv_root.join(format!("invoke-{:05}", invoke_num));
190	    let burv_output = invoke_dir.join("output");
191	    let burv_temp = invoke_dir.join("temp");
192	
193	    std::fs::create_dir_all(&burv_output)
194	        .map_err(|e| format!("rbtdri: failed to create BURV output dir: {}", e))?;
195	    std::fs::create_dir_all(&burv_temp)
196	        .map_err(|e| format!("rbtdri: failed to create BURV temp dir: {}", e))?;
197	
198	    let mut cmd = Command::new(tabtarget);
199	    cmd.args(args)
200	        .current_dir(&ctx.project_root)
201	        .env("BURV_OUTPUT_ROOT_DIR", &burv_output)
202	        .env("BURV_TEMP_ROOT_DIR", &burv_temp);
203	
204	    for (key, value) in extra_env {
205	        cmd.env(key, value);
206	    }
207	
208	    let output = cmd
209	        .output()
210	        .map_err(|e| format!("rbtdri: failed to execute '{}': {}", tabtarget.display(), e))?;
211	
212	    Ok(rbtdri_InvokeResult {
213	        stdout: String::from_utf8_lossy(&output.stdout).into_owned(),
214	        stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
215	        exit_code: output.status.code().unwrap_or(-1),
216	        burv_output,
217	    })
218	}
