254	// ── BURV fact file reading ───────────────────────────────────
255	
256	/// Read a fact file from a tabtarget's BURV output directory.
257	/// Fact files are single-line values written by tabtargets to BURD_OUTPUT_DIR,
258	/// which is BURV_OUTPUT_ROOT_DIR/current per BUK dispatch convention.
259	pub fn rbtdri_read_burv_fact(
260	    result: &rbtdri_InvokeResult,
261	    fact_name: &str,
262	) -> Result<String, String> {
263	    let path = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR).join(fact_name);
264	    let content = std::fs::read_to_string(&path)
265	        .map_err(|e| format!("rbtdri: cannot read fact '{}' from {}: {}", fact_name, path.display(), e))?;
266	    let trimmed = content.trim().to_string();
267	    if trimmed.is_empty() {
268	        return Err(format!("rbtdri: fact '{}' is empty in {}", fact_name, path.display()));
269	    }
270	    Ok(trimmed)
271	}
