273	// ── Ifrit verdict parsing ────────────────────────────────────
274	
275	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
276	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
277	/// Missing verdict line is always a failure — no silent pass-through.
278	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
279	    for line in stdout.lines() {
280	        let trimmed = line.trim();
281	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
282	            let rest = rest.trim();
283	            if rest.starts_with("PASS") {
284	                return rbtdre_Verdict::Pass;
285	            }
286	            if let Some(detail) = rest.strip_prefix("FAIL") {
287	                let detail = detail.trim();
288	                if detail.is_empty() {
289	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
290	                }
291	                return rbtdre_Verdict::Fail(detail.to_string());
292	            }
293	        }
294	    }
295	
296	    if exit_code == 0 {
297	        rbtdre_Verdict::Fail("ifrit exited 0 but no verdict line found".to_string())
298	    } else {
299	        rbtdre_Verdict::Fail(format!("ifrit exited {} with no verdict line", exit_code))
300	    }
301	}
