303	/// Invoke the ifrit binary inside a charged bottle via the bark tabtarget.
304	/// The attack selector argument tells ifrit which attack module to run.
305	/// Returns a test verdict based on ifrit's stdout verdict line and exit code.
306	pub fn rbtdri_invoke_ifrit(
307	    ctx: &mut rbtdri_Context,
308	    attack_selector: &str,
309	) -> Result<rbtdre_Verdict, String> {
310	    let result = rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRI_IFRIT_BINARY, attack_selector])?;
311	    Ok(rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code))
312	}
