        ));
    }
    let extra_env: &[(&str, &str)] = &[
        ("BURE_TWEAK_NAME", RBTDRO_GRAFT_TWEAK_NAME),
        ("BURE_TWEAK_VALUE", RBTDRO_GRAFT_SOURCE_IMAGE),
    ];
    match rbtdro_ordain_capture(ctx, dir, RBTDRO_VESSEL_DIR_GRAFT, extra_env, "ordain-graft") {
